9	    <style>
10	        :root {
11	            --blue: #0047ba;
12	            --text: #2e2e2e;
13	            --text-muted: #374151;
14	            --gray: #6B7280;
15	            --border: #E5E7EB;
16	            --page-padding: 56px;
17	            --footer-height: 120px;
18	        }
19	
20	        * { margin: 0; padding: 0; box-sizing: border-box; }
21	
22	        body {
23	            font-family: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, sans-serif;
24	            background: #D1D5DB;
25	            color: var(--text);
26	            -webkit-print-color-adjust: exact;
27	            print-color-adjust: exact;
28	            font-size: 13px;
29	            line-height: 1.75;
30	        }
31	
32	        /* ── DYNAMIC DOCUMENT CONTAINER ── */
33	        .document {
34	            max-width: 210mm;
35	            margin: 0 auto;
36	            padding: 24px 0;
37	            position: relative;
38	        }
39	
40	        /* ── DYNAMIC CONTENT FLOW ── */
41	        .content-flow {
42	            width: 210mm;
43	            background: #fcfcfc;
44	            margin: 0 auto;
45	            position: relative;
46	            overflow: visible;
47	            box-shadow: 0 2px 12px rgba(0,0,0,0.12);
48	        }
49	
50	        /* ── BACKGROUND FOR ALL PAGES ── */
51	        .content-flow::before {
52	            content: '';
53	            position: fixed;
54	            top: 0;
55	            left: 50%;
56	            transform: translateX(-50%);
57	            width: 210mm;
58	            height: 100vh;
59	            background: url('fundo-center.png') center center no-repeat;
60	            background-size: 602px auto;
61	            opacity: 0.035;
62	            pointer-events: none;
63	            z-index: 0;
64	        }
65	
66	        /* ── PAGE STRUCTURE ── */
67	        .page-content {
68	            position: relative;
69	            z-index: 1;
70	            padding: 46px var(--page-padding) var(--footer-height);
71	            min-height: 297mm;
72	            page-break-after: always;
73	        }
74	
75	        /* ── COVER PAGE SPECIFIC ── */
76	        .cover-page {
77	            page-break-after: always;
78	            break-after: page;
79	            position: relative;
80	        }
81	
82	        .cover-page .page-content {
83	            display: flex;
84	            flex-direction: column;
85	            justify-content: flex-start;
86	        }
87	
88	        /* ── HIDE LOGO ON CONTINUOUS PAGES ── */
89	        .flow-page .logo {
90	            display: none;
91	        }
92	
93	        /* ── CONTINUOUS CONTENT PAGES ── */
94	        .flow-page {
95	            page-break-inside: auto;
96	        }
97	
98	        .flow-page:last-of-type {
99	            page-break-after: auto;
100	        }

